module top_module(
    input signed [17:0] A,
    input signed [17:0] B,
    output reg signed [35:0] P,
    (* clkbuf_sink *)
    input C,
    input CE,
    input R
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge C or posedge dbg_halt)
	if (R)
		P <= 0;
	else if (CE)
		P <= A * B;

endmodule
